package v1

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/stretchr/testify/require"
)

// SilenceRequest represents a silence to be created
type SilenceRequest struct {
	Matchers  []Matcher `json:"matchers"`
	StartsAt  time.Time `json:"startsAt"`
	EndsAt    time.Time `json:"endsAt"`
	CreatedBy string    `json:"createdBy"`
	Comment   string    `json:"comment"`
}

// Matcher represents a label matcher
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
	IsEqual bool   `json:"isEqual"`
}

// SilenceResponse represents the response after creating a silence
type SilenceResponse struct {
	ID string `json:"id"`
}

// BulkSilenceResponse represents the response from bulk silence creation
type BulkSilenceResponse struct {
	IDs []string `json:"ids"`
}

// BulkSilenceErrorResponse represents an error response for bulk silence creation
type BulkSilenceErrorResponse struct {
	Error string `json:"error"`
	Index int    `json:"index"`
}

func TestSilencesBulk(t *testing.T) {
	tests := []struct {
		name           string
		silences       []SilenceRequest
		expectedStatus int
		expectedError  bool
		errorIndex     int
		description    string
	}{
		{
			name: "successful bulk creation",
			silences: []SilenceRequest{
				{
					Matchers: []Matcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "test silence",
				},
				{
					Matchers: []Matcher{
						{Name: "job", Value: "test-job", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(2 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "another test silence",
				},
			},
			expectedStatus: http.StatusOK,
			expectedError:  false,
			description:    "Should successfully create multiple silences",
		},
		{
			name:           "empty array",
			silences:       []SilenceRequest{},
			expectedStatus: http.StatusOK,
			expectedError:  false,
			description:    "Should handle empty array",
		},
		{
			name: "validation failure - bad matchers",
			silences: []SilenceRequest{
				{
					Matchers:  []Matcher{}, // Empty matchers is invalid
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "invalid silence",
				},
			},
			expectedStatus: http.StatusBadRequest,
			expectedError:  true,
			errorIndex:     0,
			description:    "Should fail validation with empty matchers",
		},
		{
			name: "partial validation failure",
			silences: []SilenceRequest{
				{
					Matchers: []Matcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "valid silence",
				},
				{
					Matchers:  []Matcher{}, // This one is invalid
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(2 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "invalid silence",
				},
			},
			expectedStatus: http.StatusBadRequest,
			expectedError:  true,
			errorIndex:     1,
			description:    "Should stop at first validation failure and report index",
		},
		{
			name: "invalid time range",
			silences: []SilenceRequest{
				{
					Matchers: []Matcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now().Add(2 * time.Hour),
					EndsAt:    time.Now().Add(1 * time.Hour), // EndsAt before StartsAt
					CreatedBy: "test-user",
					Comment:   "invalid time range",
				},
			},
			expectedStatus: http.StatusBadRequest,
			expectedError:  true,
			errorIndex:     0,
			description:    "Should fail when EndsAt is before StartsAt",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Create the API instance
			api := &API{
				logger: nil,
			}

			// Encode the silences as JSON
			body, err := json.Marshal(tt.silences)
			require.NoError(t, err)

			// Create a request
			req, err := http.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
			require.NoError(t, err)
			req.Header.Set("Content-Type", "application/json")

			// Create a response recorder
			w := httptest.NewRecorder()

			// Call the handler
			result := api.silencesBulk(req)

			// Check the result
			if tt.expectedError {
				require.NotNil(t, result.err, "Expected error but got none")
				// The error should be a bad data error
				require.Equal(t, errorBadData, result.err.typ)
			} else {
				require.Nil(t, result.err, "Expected no error but got: %v", result.err)
				require.NotNil(t, result.data, "Expected data but got nil")

				// For successful creation, data should contain IDs
				if len(tt.silences) > 0 {
					bulkResp, ok := result.data.(BulkSilenceResponse)
					require.True(t, ok, "Expected BulkSilenceResponse but got %T", result.data)
					require.Equal(t, len(tt.silences), len(bulkResp.IDs), "Expected %d IDs but got %d", len(tt.silences), len(bulkResp.IDs))

					// Verify all IDs are non-empty
					for i, id := range bulkResp.IDs {
						require.NotEmpty(t, id, "ID at index %d is empty", i)
					}
				}
			}
		})
	}
}

