	tests := []struct {
		name          string
		silences      []silenceRequest
		expectedError bool
		description   string
	}{
		{
			name: "successful bulk creation",
			silences: []silenceRequest{
				{
					Matchers: []silenceMatcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "test silence",
				},
				{
					Matchers: []silenceMatcher{
						{Name: "job", Value: "test-job", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(2 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "another test silence",
				},
			},
			expectedError: false,
			description:   "Should successfully create multiple silences",
		},
		{
			name:          "empty array",
			silences:      []silenceRequest{},
			expectedError: false,
			description:   "Should handle empty array",
		},
		{
			name: "validation failure - bad matchers",
			silences: []silenceRequest{
				{
					Matchers:  []silenceMatcher{}, // Empty matchers is invalid
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "invalid silence",
				},
			},
			expectedError: true,
			description:   "Should fail validation with empty matchers",
		},
		{
			name: "partial validation failure",
			silences: []silenceRequest{
				{
					Matchers: []silenceMatcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "valid silence",
				},
				{
					Matchers:  []silenceMatcher{}, // This one is invalid
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(2 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "invalid silence",
				},
			},
			expectedError: true,
			description:   "Should stop at first validation failure and report index",
		},
		{
			name: "invalid time range",
			silences: []silenceRequest{
				{
					Matchers: []silenceMatcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now().Add(2 * time.Hour),
					EndsAt:    time.Now().Add(1 * time.Hour), // EndsAt before StartsAt
					CreatedBy: "test-user",
					Comment:   "invalid time range",
				},
			},
			expectedError: true,
			description:   "Should fail when EndsAt is before StartsAt",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Create the API instance
			api := &API{}

			// Encode the silences as JSON
			body, err := json.Marshal(tt.silences)
			require.NoError(t, err)

			// Create a request
			req, err := http.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
			require.NoError(t, err)
			req.Header.Set("Content-Type", "application/json")

			// Call the handler
			result := api.silencesBulk(req)

			// Check the result
			if tt.expectedError {
				require.NotNil(t, result.err, "Expected error but got none: %s", tt.description)
				// The error should be a bad data error
				require.Equal(t, errorBadData, result.err.typ, "Expected bad data error: %s", tt.description)
			} else {
				require.Nil(t, result.err, "Expected no error but got: %v (%s)", result.err, tt.description)
				require.NotNil(t, result.data, "Expected data but got nil: %s", tt.description)

				// For successful creation, data should contain IDs
				if len(tt.silences) > 0 {
					// The response is an anonymous struct with IDs field
					dataMap, ok := result.data.(map[string]interface{})
					if !ok {
						// Try to marshal and unmarshal to get the structure
						jsonBytes, err := json.Marshal(result.data)
						require.NoError(t, err)
						var response map[string]interface{}
						err = json.Unmarshal(jsonBytes, &response)
						require.NoError(t, err)
						dataMap = response
					}

					// Get the IDs from the response
					idsInterface, ok := dataMap["IDs"]
					require.True(t, ok, "Expected 'IDs' field in response: %s", tt.description)
					ids, ok := idsInterface.([]interface{})
					require.True(t, ok, "Expected IDs to be an array: %s", tt.description)
					require.Equal(t, len(tt.silences), len(ids), "Expected %d IDs but got %d: %s", len(tt.silences), len(ids), tt.description)

					// Verify all IDs are non-empty
					for i, id := range ids {
						require.NotEmpty(t, id, "ID at index %d is empty: %s", i, tt.description)
					}
				}
			}
		})
	}
}

