	tests := []struct {
		name           string
		silences       []SilenceRequest
		expectedStatus int
		expectedError  bool
		errorIndex     int
		description    string
	}{
		{
			name: "successful bulk creation",
			silences: []SilenceRequest{
				{
					Matchers: []Matcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "test silence",
				},
				{
					Matchers: []Matcher{
						{Name: "job", Value: "test-job", IsRegex: false, IsEqual: true},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(2 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "another test silence",
				},
			},
			expectedStatus: http.StatusOK,
			expectedError:  false,
			description:    "Should successfully create multiple silences",
		},
		{
			name:           "empty array",
			silences:       []SilenceRequest{},
			expectedStatus: http.StatusOK,
			expectedError:  false,
			description:    "Should handle empty array",
		},
		{
			name: "validation failure - bad matchers",
			silences: []SilenceRequest{
				{
					Matchers:  []Matcher{}, // Empty matchers is invalid
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "invalid silence",
